+    #[test]
+    fn expiry_ms_just_over_i64_max_saturates() {
+        // Just barely overflowing u64 multiply should saturate to i64::MAX
+        let secs = (i64::MAX as u64) / 1000 + 2;
+        let result = expiry_ms(secs);
+        // The result should still be representable
+        assert!(result > 0);
+    }
